import React from 'react';
import { SectionConfig } from './section-schemas';
import { HeroSection } from '@/components/builder-sections/HeroSection';
import { FeaturesSection } from '@/components/builder-sections/FeaturesSection';
import CTASection from '@/components/builder-sections/CTASection';
import { TabsSection } from '@/components/builder-sections/TabsSection';
import FAQSection from '@/components/builder-sections/FAQSection';
import HeroVideoSection from '@/components/builder-sections/HeroVideoSection';
import HeroAnimatedSection from '@/components/builder-sections/HeroAnimatedSection';
import TimelineSection from '@/components/builder-sections/TimelineSection';
import PricingSection from '@/components/builder-sections/PricingSection';
import StatsSection from '@/components/builder-sections/StatsSection';
import TestimonialSection from '@/components/builder-sections/TestimonialSection';
import FeatureGridSection from '@/components/builder-sections/FeatureGridSection';
import TeamSection from '@/components/builder-sections/TeamSection';
import IndustryHeroSection from '@/components/builder-sections/IndustryHeroSection';
import BenefitGridSection from '@/components/builder-sections/BenefitGridSection';
import CaseStudySection from '@/components/builder-sections/CaseStudySection';
import IndustryFeaturesSection from '@/components/builder-sections/IndustryFeaturesSection';
import FeatureCardsSection from '@/components/builder-sections/FeatureCardsSection';
import IndustryCardsSection from '@/components/builder-sections/IndustryCardsSection';
import PropertiesSection from '@/components/builder-sections/PropertiesSection';
import LocationSection from '@/components/builder-sections/LocationSection';
import TestimonialsSection from '@/components/builder-sections/TestimonialsSection';
import WorkflowSection from '@/components/builder-sections/WorkflowSection';
import IntegrationsSection from '@/components/builder-sections/IntegrationsSection';
import ProcessSection from '@/components/builder-sections/ProcessSection';
import { ComplianceBadgesSection } from '@/components/builder-sections/ComplianceBadgesSection';

interface SectionRendererProps {
  section: SectionConfig;
  isBuilder?: boolean;
  isSelected?: boolean;
  onSelect?: () => void;
}

export function SectionRenderer({ 
  section, 
  isBuilder = false, 
  isSelected = false, 
  onSelect 
}: SectionRendererProps) {
  const commonProps = {
    section,
    isBuilder,
    isSelected,
    onSelect,
  };

  // Wrapper for builder mode
  const WrapperComponent = isBuilder ? BuilderSectionWrapper : React.Fragment;
  const wrapperProps = isBuilder ? { isSelected, onSelect } : {};

  const renderSection = () => {
    switch (section.type) {
      case 'hero':
        return <HeroSection section={section as any} isBuilder={isBuilder} />;
      case 'hero-video':
        return <HeroVideoSection section={section as any} isBuilder={isBuilder} />;
      case 'hero-animated':
        return <HeroAnimatedSection section={section as any} isBuilder={isBuilder} />;
      case 'features':
        return <FeaturesSection section={section as any} isBuilder={isBuilder} />;
      case 'cta':
        return <CTASection data={(section as any).data} style={(section as any).style} />;
      case 'tabs':
        return <TabsSection section={section as any} isBuilder={isBuilder} />;
      case 'faq':
        return <FAQSection data={(section as any).data} style={(section as any).style} />;
      case 'timeline':
        return <TimelineSection section={section as any} isBuilder={isBuilder} />;
      case 'pricing':
        return <PricingSection section={section as any} isBuilder={isBuilder} />;
      case 'stats':
        return <StatsSection section={section as any} isBuilder={isBuilder} />;
      case 'testimonial':
        return <TestimonialSection data={(section as any).data} style={(section as any).style} />;
      case 'feature-grid':
        return <FeatureGridSection data={(section as any).data} style={(section as any).style} />;
      case 'team':
        return <TeamSection data={(section as any).data} style={(section as any).style} />;
      case 'industry-hero':
        return <IndustryHeroSection section={section as any} isBuilder={isBuilder} />;
      case 'benefit-grid':
        return <BenefitGridSection data={(section as any).data} style={(section as any).style} />;
      case 'case-study':
        return <CaseStudySection data={(section as any).data} style={(section as any).style} />;
      case 'industry-features':
        return <IndustryFeaturesSection data={(section as any).data} style={(section as any).style} />;
      case 'feature-cards':
        return <FeatureCardsSection data={(section as any).data} style={(section as any).style} />;
      case 'industry-cards':
        return <IndustryCardsSection data={(section as any).data} style={(section as any).style} />;
      case 'properties':
        return <PropertiesSection data={(section as any).data} style={(section as any).style} />;
      case 'location':
        return <LocationSection data={(section as any).data} style={(section as any).style} />;
      case 'testimonials':
        return <TestimonialsSection data={(section as any).data} style={(section as any).style} />;
      case 'workflow':
        return <WorkflowSection data={(section as any).data} style={(section as any).style} />;
      case 'integrations':
        return <IntegrationsSection data={(section as any).data} style={(section as any).style} />;
      case 'process':
        return <ProcessSection data={(section as any).data} style={(section as any).style} />;
      case 'compliance':
        return <ComplianceBadgesSection data={(section as any).data} />;
      default:
        return (
          <div className="p-8 bg-gray-100 dark:bg-gray-800 text-center">
            <p className="text-gray-600 dark:text-gray-400">
              Unknown section type: {section.type}
            </p>
          </div>
        );
    }
  };

  return (
    <WrapperComponent {...wrapperProps}>
      {renderSection()}
    </WrapperComponent>
  );
}

// Builder wrapper component for selection and editing
function BuilderSectionWrapper({ 
  children, 
  isSelected, 
  onSelect 
}: { 
  children: React.ReactNode;
  isSelected?: boolean;
  onSelect?: () => void;
}) {
  return (
    <div
      className={`relative group cursor-pointer transition-all duration-200 ${
        isSelected 
          ? 'ring-2 ring-blue-500 ring-offset-2' 
          : 'hover:ring-2 hover:ring-blue-300 hover:ring-offset-2'
      }`}
      onClick={onSelect}
    >
      {children}
      
      {/* Builder overlay */}
      <div className={`absolute inset-0 bg-blue-500/10 transition-opacity duration-200 ${
        isSelected ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'
      }`} />
      
      {/* Section controls */}
      <div className={`absolute top-2 right-2 flex space-x-1 transition-opacity duration-200 ${
        isSelected ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'
      }`}>
        <button className="p-1 bg-white dark:bg-gray-800 rounded shadow-sm hover:bg-gray-50 dark:hover:bg-gray-700">
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
          </svg>
        </button>
        <button className="p-1 bg-white dark:bg-gray-800 rounded shadow-sm hover:bg-gray-50 dark:hover:bg-gray-700">
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
          </svg>
        </button>
      </div>
    </div>
  );
}

// Render multiple sections
export function renderSections(
  sections: SectionConfig[], 
  isBuilder = false,
  selectedSectionId?: string,
  onSectionSelect?: (sectionId: string) => void
) {
  return sections
    .sort((a, b) => a.order - b.order)
    .map((section) => (
      <SectionRenderer
        key={section.id}
        section={section}
        isBuilder={isBuilder}
        isSelected={selectedSectionId === section.id}
        onSelect={() => onSectionSelect?.(section.id)}
      />
    ));
}